// Find matching backend service for a given path
function findBackendService(requestPath) {
  for (const [prefix, config] of Object.entries(BACKEND_SERVICES)) {
    if (requestPath.startsWith(prefix)) {
      return { prefix, ...config };
    }
  }
  return null;
}

// Proxy middleware - forwards requests to backend services
async function proxyRequest(req, res) {
  const service = findBackendService(req.path);

  if (!service) {
    debugLog('No matching backend service found', {
      path: req.path,
      api_key: req.authenticatedApiKey
    });
    return res.status(404).json({
      error: 'Not Found',
      message: `No backend service configured for path: ${req.path}`
    });
  }

  // Build the target URL - strip the service prefix and forward the rest
  const targetPath = req.path.substring(service.prefix.length) || '/';

  // Build query string without api_key (it will be forwarded in headers)
  const queryParams = { ...req.query };
  delete queryParams.api_key;
  const queryString = new URLSearchParams(queryParams).toString();
  const targetUrl = `${service.target}${targetPath}${queryString ? '?' + queryString : ''}`;

  // Build headers to forward
  const forwardHeaders = {
    'X-API-Key': req.authenticatedApiKey,
    'X-Forwarded-For': req.ip,
    'X-Forwarded-Host': req.hostname,
    'X-Forwarded-Proto': req.protocol,
    'X-Gateway-Request-Id': generateRequestId(),
    'Content-Type': req.headers['content-type'] || 'application/json',
    'Accept': req.headers['accept'] || 'application/json',
    'User-Agent': req.headers['user-agent'] || 'API-Gateway/1.0'
  };

  // Forward authorization header if present
  if (req.headers['authorization']) {
    forwardHeaders['Authorization'] = req.headers['authorization'];
  }

  debugLog('Forwarding request to backend service', {
    service: service.name,
    targetUrl,
    method: req.method,
    api_key: req.authenticatedApiKey,
    forwardHeaders: {
      'X-API-Key': forwardHeaders['X-API-Key'],
      'X-Gateway-Request-Id': forwardHeaders['X-Gateway-Request-Id'],
      'X-Forwarded-For': forwardHeaders['X-Forwarded-For']
    }
  });

  try {
    const axiosConfig = {
      method: req.method.toLowerCase(),
      url: targetUrl,
      headers: forwardHeaders,
      timeout: 30000, // 30 second timeout
      validateStatus: () => true // Don't throw on any status code
    };

    // Forward request body for non-GET requests
    if (['POST', 'PUT', 'PATCH'].includes(req.method) && req.body) {
      axiosConfig.data = req.body;
    }

    const startTime = Date.now();
    const response = await axios(axiosConfig);
    const duration = Date.now() - startTime;

    debugLog('Backend service response received', {
      service: service.name,
      targetUrl,
      statusCode: response.status,
      duration_ms: duration,
      api_key: req.authenticatedApiKey,
      responseHeaders: {
        'content-type': response.headers['content-type'],
        'content-length': response.headers['content-length']
      }
    });

    // Forward response headers from backend
    const headersToForward = [
      'content-type',
      'cache-control',
      'etag',
      'last-modified',
      'x-request-id',
      'x-ratelimit-limit',
      'x-ratelimit-remaining'
    ];

    headersToForward.forEach(header => {
      if (response.headers[header]) {
        res.set(header, response.headers[header]);
      }
    });

    // Add gateway headers
    res.set('X-Gateway-Service', service.name);
    res.set('X-Gateway-Duration', `${duration}ms`);

    res.status(response.status).send(response.data);

  } catch (error) {
    debugLog('Backend service request failed', {
      service: service.name,
      targetUrl,
      error: error.message,
      code: error.code,
      api_key: req.authenticatedApiKey
    });

    if (error.code === 'ECONNREFUSED') {
      return res.status(503).json({
        error: 'Service Unavailable',
        message: `Backend service "${service.name}" is not available.`,
        service: service.name
      });
    }

    if (error.code === 'ECONNABORTED' || error.code === 'ETIMEDOUT') {
      return res.status(504).json({
        error: 'Gateway Timeout',
        message: `Request to "${service.name}" timed out.`,
        service: service.name
      });
    }

    res.status(502).json({
      error: 'Bad Gateway',
      message: `Error communicating with backend service "${service.name}".`,
      service: service.name
    });
  }
}

// Generate a unique request ID
